#include <numeric>
#include <cmath>
#include <algorithm>

using namespace std;

/**
 * @brief Solves the problem of counting connected induced subgraphs with even sum.
 * 
 * @param nums An array where nums[i] is the value (0 or 1) of node i.
 * @param edges A list of edges in the undirected graph.
 * @return int64 The number of non-empty subsets s satisfying the conditions.
 */
int64 solve(vector<int64> nums, vector<vector<int64>> edges) {
    int n = nums.size();
    int64 count = 0;

    // Build adjacency list for the graph
    vector<vector<int>> adj(n);
    for (const auto& edge : edges) {
        int u = edge[0];
        int v = edge[1];
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    // Iterate through all non-empty subsets s, represented by a bitmask
    // There are 2^n - 1 non-empty subsets. Since n <= 13, 2^13 is small enough.
    for (int mask = 1; mask < (1 << n); ++mask) {

        // 1. Check if the sum of values in s is even
        int64 sum = 0;
        for (int i = 0; i < n; ++i) {
            if ((mask >> i) & 1) {
                sum += nums[i];
            }
        }

        if (sum % 2 != 0) {
            continue; // Skip if the sum is odd
        }

        // 2. Check if the induced subgraph is connected

        // Find the first node in the subset s
        int start_node = -1;
        for (int i = 0; i < n; ++i) {
            if ((mask >> i) & 1) {
                start_node = i;
                break;
            }
        }

        // Perform BFS or DFS starting from start_node, only traversing to nodes in s
        vector<bool> visited(n, false);
        vector<int> queue;
        queue.push_back(start_node);
        visited[start_node] = true;
        int head = 0;
        int visited_count = 0;

        while (head < queue.size()) {
            int u = queue[head++];
            visited_count++;

            for (int v : adj[u]) {
                // Check if v is in the subset s AND v has not been visited
                if (((mask >> v) & 1) && !visited[v]) {
                    visited[v] = true;
                    queue.push_back(v);
                }
            }
        }

        // The induced subgraph is connected if the number of nodes reached equals the size of the subset s
        // The size of the subset s is the number of set bits in 'mask'.
        int subset_size = 0;
        for (int i = 0; i < n; ++i) {
            if ((mask >> i) & 1) {
                subset_size++;
            }
        }

        if (visited_count == subset_size) {
            // Both conditions met: connected AND even sum
            count++;
        }
    }

    return count;
}
